// SysMoBench etcd task — trace harness.
//
// Produces the NDJSON event stream that SysMoBench's transition-validation
// phase consumes, by driving a real three-node etcd Raft cluster and recording
// every state-machine event the library reports.
//
// WHY THIS EXISTS. SysMoBench's etcd task points at `data/sys_traces/etcd`,
// which the benchmark does not ship: traces are generated, not distributed, and
// the per-task instrumentation is generated by a harness skill that is likewise
// not shipped. The only committed piece is a patch adding a tracer injection
// point to the library's own test rig. This file is the missing piece, written
// against the tracing facility that IS upstream and maintained.
//
// WHAT IT DOES NOT DO. It does not modify etcd. `state_trace.go` lives in
// etcd-io/raft behind the `with_tla` build tag and declares the `TraceLogger`
// interface and the `TracingEvent` payload; a `!with_tla` twin stubs both out
// so the facility costs nothing in production builds. We depend on the library
// as a normal module and build with `-tags with_tla`, so the events recorded
// here are the library's own, emitted from its own call sites, with no patched
// or reimplemented logic in between. That is the whole point: the corpus has to
// be ground truth from executed code, not from our idea of what etcd does.
//
//	go run -tags with_tla . -out traces/etcd.ndjson
//
// Determinism: the cluster is driven through `RawNode`, the synchronous API, in
// a single goroutine with a fixed tick schedule and in-order message delivery.
// There is no wall-clock dependence and no scheduler nondeterminism, so the
// same build produces the same trace. (The library's own `traceReceiveMessage`
// contains a 1ms sleep to spread timestamps across nodes; we do not read
// timestamps, so it does not affect the recorded sequence.)
package main

import (
	"bufio"
	"encoding/json"
	"flag"
	"fmt"
	"os"
	"path/filepath"

	"go.etcd.io/raft/v3"
	"go.etcd.io/raft/v3/raftpb"
)

// recorder implements raft.TraceLogger. Every event the library emits is
// written verbatim as one NDJSON line, with a monotonic sequence number so the
// downstream mapper can order events across nodes without relying on clocks.
type recorder struct {
	w   *bufio.Writer
	seq int
}

func (r *recorder) TraceEvent(e *raft.TracingEvent) {
	// The event is marshalled as the library defines it. We add `seq` only;
	// nothing about the payload is reinterpreted here, because any reshaping
	// done at capture time is a place a capture bug can hide.
	raw, err := json.Marshal(e)
	if err != nil {
		panic(fmt.Sprintf("marshal tracing event: %v", err))
	}
	var m map[string]any
	if err := json.Unmarshal(raw, &m); err != nil {
		panic(fmt.Sprintf("re-read tracing event: %v", err))
	}
	m["seq"] = r.seq
	r.seq++
	out, err := json.Marshal(m)
	if err != nil {
		panic(fmt.Sprintf("remarshal tracing event: %v", err))
	}
	r.w.Write(out)
	r.w.WriteByte('\n')
}

type peerNode struct {
	id      uint64
	storage *raft.MemoryStorage
	rn      *raft.RawNode
}

func main() {
	out := flag.String("out", "traces/etcd.ndjson", "NDJSON trace output path")
	proposals := flag.Int("proposals", 6, "client proposals to submit once a leader is elected")
	maxSteps := flag.Int("max-steps", 4000, "safety bound on driver iterations")
	flag.Parse()

	if !raft.StateTraceDeployed {
		fmt.Fprintln(os.Stderr,
			"refusing to run: raft.StateTraceDeployed is false, so the library was built WITHOUT -tags with_tla.\n"+
				"Every trace call is a no-op in that build and this harness would silently write an empty corpus.\n"+
				"Re-run as: go run -tags with_tla . -out <path>")
		os.Exit(2)
	}

	if err := os.MkdirAll(filepath.Dir(*out), 0o755); err != nil {
		fmt.Fprintf(os.Stderr, "mkdir: %v\n", err)
		os.Exit(1)
	}
	f, err := os.Create(*out)
	if err != nil {
		fmt.Fprintf(os.Stderr, "create %s: %v\n", *out, err)
		os.Exit(1)
	}
	defer f.Close()
	bw := bufio.NewWriter(f)
	defer bw.Flush()
	rec := &recorder{w: bw}

	peers := []raft.Peer{{ID: 1}, {ID: 2}, {ID: 3}}
	nodes := map[uint64]*peerNode{}
	for _, p := range peers {
		st := raft.NewMemoryStorage()
		cfg := &raft.Config{
			ID:            p.ID,
			ElectionTick:  10,
			HeartbeatTick: 1,
			Storage:       st,
			// Bounded so replication stays legible in the trace rather than
			// coalescing into a few very large batches.
			MaxSizePerMsg:             1024 * 1024,
			MaxInflightMsgs:           256,
			MaxUncommittedEntriesSize: 1 << 30,
			TraceLogger:               rec,
		}
		rn, err := raft.NewRawNode(cfg)
		if err != nil {
			fmt.Fprintf(os.Stderr, "NewRawNode(%d): %v\n", p.ID, err)
			os.Exit(1)
		}
		if err := rn.Bootstrap(peers); err != nil {
			fmt.Fprintf(os.Stderr, "Bootstrap(%d): %v\n", p.ID, err)
			os.Exit(1)
		}
		nodes[p.ID] = &peerNode{id: p.ID, storage: st, rn: rn}
	}
	order := []uint64{1, 2, 3}

	// The scenario is chosen to exercise every action the SysMoBench etcd task
	// declares in scope: an election (ElectionTimeout, vote request/response),
	// client proposals (ClientProposal, replicate), the resulting append-entries
	// traffic, and the heartbeats that follow. A trace that never elects a
	// leader would exercise a third of the contract and still look like a corpus.
	inbox := []raftpb.Message{}
	leader := uint64(0)
	proposed := 0

	// One round of message delivery followed by one drain of every node's
	// readiness. Returns true if anything at all happened, so callers can
	// settle the cluster without a fixed guess at how many rounds that takes.
	round := func() bool {
		busy := false
		pending := inbox
		inbox = nil
		for _, m := range pending {
			busy = true
			if n, ok := nodes[m.To]; ok {
				// A dropped proposal on a non-leader is normal Raft behaviour,
				// not a harness failure.
				if err := n.rn.Step(m); err != nil && err != raft.ErrProposalDropped {
					fmt.Fprintf(os.Stderr, "step to %d: %v\n", m.To, err)
				}
			}
		}
		for _, id := range order {
			n := nodes[id]
			if !n.rn.HasReady() {
				continue
			}
			busy = true
			rd := n.rn.Ready()
			if !raft.IsEmptyHardState(rd.HardState) {
				n.storage.SetHardState(rd.HardState)
			}
			if len(rd.Entries) > 0 {
				n.storage.Append(rd.Entries)
			}
			inbox = append(inbox, rd.Messages...)
			for _, e := range rd.CommittedEntries {
				if e.Type == raftpb.EntryConfChange {
					var cc raftpb.ConfChange
					if err := cc.Unmarshal(e.Data); err == nil {
						n.rn.ApplyConfChange(cc)
					}
				}
			}
			n.rn.Advance(rd)
			if leader == 0 && n.rn.Status().RaftState == raft.StateLeader {
				leader = id
			}
		}
		return busy
	}
	settle := func(bound int) {
		for i := 0; i < bound; i++ {
			if !round() {
				return
			}
		}
	}

	// The scenario runs in explicit phases rather than one undifferentiated
	// loop. An earlier version ticked the leader on every iteration and gated
	// proposals on an empty inbox, which meant heartbeat traffic kept the inbox
	// permanently non-empty: it produced forty-three thousand events, all
	// election and heartbeat, and NOT ONE client proposal. The corpus looked
	// substantial and exercised two thirds of the declared actions. Phases make
	// the coverage a property of the code rather than of a race between a tick
	// schedule and a queue.

	// Phase 1 — election. Only node 1 is ticked, so the election is decided
	// rather than contended; a split vote is a valid trace but a poorer first
	// corpus.
	for i := 0; i < *maxSteps && leader == 0; i++ {
		nodes[1].rn.Tick()
		settle(200)
	}
	if leader == 0 {
		fmt.Fprintln(os.Stderr, "FAILED: no leader was elected — the trace does not exercise the declared actions")
		os.Exit(1)
	}

	// Phase 2 — client proposals, one per settled round, so each appears in the
	// trace as its own replication round rather than a coalesced batch.
	for proposed < *proposals {
		data := []byte(fmt.Sprintf("v%d", proposed))
		if err := nodes[leader].rn.Propose(data); err != nil && err != raft.ErrProposalDropped {
			fmt.Fprintf(os.Stderr, "propose: %v\n", err)
		}
		proposed++
		settle(200)
	}

	// Phase 3 — heartbeats. HandleHeartbeat is a declared action, and after the
	// proposals have settled the leader must tick for any to be emitted.
	for i := 0; i < 3; i++ {
		nodes[leader].rn.Tick()
		settle(200)
	}

	if err := bw.Flush(); err != nil {
		fmt.Fprintf(os.Stderr, "flush: %v\n", err)
		os.Exit(1)
	}

	// A harness that writes an empty or leaderless corpus has failed, and must
	// say so rather than leaving a plausible-looking file behind.
	if leader == 0 {
		fmt.Fprintln(os.Stderr, "FAILED: no leader was elected — the trace does not exercise the declared actions")
		os.Exit(1)
	}
	if rec.seq == 0 {
		fmt.Fprintln(os.Stderr, "FAILED: zero events recorded")
		os.Exit(1)
	}
	fmt.Printf("leader=%d proposals=%d events=%d -> %s\n", leader, proposed, rec.seq, *out)
}
